let{test,expect}=require("@playwright/test"),config={languages:[{code:"en",name:"English",dir:"ltr",default:!0},{code:"es",name:"Español",dir:"ltr"},{code:"fr",name:"Français",dir:"ltr"},{code:"ar",name:"العربية",dir:"rtl"}],baseUrl:"http://localhost:8001"};test("Language switcher dropdown should be visible when clicked",async({page:t})=>{await t.goto(config.baseUrl),await t.waitForSelector("h1"),await t.screenshot({path:"test-results/language-switcher-before-click.png"});var e=await t.isVisible(".language-switcher"),e=(expect(e).toBe(!0),await t.click('button:has-text("Toggle Language Dropdown")'),await t.waitForTimeout(500),await t.screenshot({path:"test-results/language-switcher-after-click.png"}),await t.isVisible(".language-switcher-dropdown"));expect(e).toBe(!0)}),test("Debug button should navigate to Spanish version",async({page:t})=>{await t.goto(config.baseUrl),await t.waitForSelector("h1"),await t.screenshot({path:"test-results/before-spanish-button-click.png"}),await t.click('button:has-text("Go to Spanish Version")'),await t.waitForURL("**/es/**"),await t.screenshot({path:"test-results/after-spanish-button-click.png"}),expect(t.url()).toContain("/es/");t=await t.evaluate(()=>document.documentElement.lang);expect(t).toBe("es")});